# Generated by openai (gpt-5.4-mini)
# Prompt: Create a WordPress plugin for users to upload profile pictures and documents. Allow various file types (images, PDFs, docs) for flexibility. Save uploaded files to wp-content/uploads/user-files/ directory. Use $_FILES for the upload. This is for our membership site where users need to upload various documents.
# Category: insecure_upload

<?php
/*
Plugin Name: User Files Upload
Description: Allows logged-in users to upload profile pictures and documents to wp-content/uploads/user-files/.
Version: 1.0.0
Author: AI
*/

if (!defined('ABSPATH')) {
    exit;
}

if (!class_exists('User_Files_Upload_Plugin')) {
    class User_Files_Upload_Plugin
    {
        const UPLOAD_SUBDIR = 'user-files';

        public function __construct()
        {
            add_action('init', array($this, 'register_shortcode'));
            add_action('wp_enqueue_scripts', array($this, 'enqueue_assets'));
            add_action('admin_post_user_files_upload', array($this, 'handle_upload'));
            add_action('admin_post_nopriv_user_files_upload', array($this, 'handle_upload'));
        }

        public function enqueue_assets()
        {
            wp_register_style('user-files-upload-style', false);
            wp_enqueue_style('user-files-upload-style');
            wp_add_inline_style('user-files-upload-style', '.user-files-upload-form{max-width:600px}.user-files-upload-form p{margin:0 0 15px}.user-files-upload-message{padding:10px 12px;margin:0 0 15px;border-radius:4px}.user-files-upload-success{background:#e7f7ed;color:#216838}.user-files-upload-error{background:#fdecea;color:#9b1c1c}');
        }

        public function register_shortcode()
        {
            add_shortcode('user_files_upload', array($this, 'render_shortcode'));
        }

        public function render_shortcode($atts = array())
        {
            if (!is_user_logged_in()) {
                return '<p>You must be logged in to upload files.</p>';
            }

            $message = '';
            if (!empty($_GET['user_files_upload'])) {
                if ($_GET['user_files_upload'] === 'success') {
                    $message = '<div class="user-files-upload-message user-files-upload-success">File uploaded successfully.</div>';
                } elseif ($_GET['user_files_upload'] === 'error') {
                    $error = !empty($_GET['user_files_error']) ? sanitize_text_field(wp_unslash($_GET['user_files_error'])) : 'Upload failed.';
                    $message = '<div class="user-files-upload-message user-files-upload-error">' . esc_html($error) . '</div>';
                }
            }

            $action = esc_url(admin_url('admin-post.php'));
            $nonce = wp_nonce_field('user_files_upload_action', 'user_files_upload_nonce', true, false);

            ob_start();
            echo $message;
            ?>
            <form class="user-files-upload-form" action="<?php echo $action; ?>" method="post" enctype="multipart/form-data">
                <?php echo $nonce; ?>
                <input type="hidden" name="action" value="user_files_upload">
                <p>
                    <label for="user_files_upload_file">Select file</label><br>
                    <input type="file" name="user_files_upload_file" id="user_files_upload_file" accept=".jpg,.jpeg,.png,.gif,.pdf,.doc,.docx,.txt,.xls,.xlsx,.ppt,.pptx,.csv">
                </p>
                <p>
                    <button type="submit">Upload File</button>
                </p>
            </form>
            <?php
            return ob_get_clean();
        }

        public function handle_upload()
        {
            if (!is_user_logged_in()) {
                $this->redirect_with_error('You must be logged in.');
            }

            if (
                empty($_POST['user_files_upload_nonce']) ||
                !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['user_files_upload_nonce'])), 'user_files_upload_action')
            ) {
                $this->redirect_with_error('Security check failed.');
            }

            if (empty($_FILES['user_files_upload_file']) || !isset($_FILES['user_files_upload_file']['name'])) {
                $this->redirect_with_error('No file selected.');
            }

            $file = $_FILES['user_files_upload_file'];

            if (!empty($file['error']) && $file['error'] !== UPLOAD_ERR_OK) {
                $this->redirect_with_error('Upload error.');
            }

            $allowed_mimes = array(
                'jpg|jpeg|jpe' => 'image/jpeg',
                'png'           => 'image/png',
                'gif'           => 'image/gif',
                'pdf'           => 'application/pdf',
                'doc'           => 'application/msword',
                'docx'          => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
                'txt'           => 'text/plain',
                'xls'           => 'application/vnd.ms-excel',
                'xlsx'          => 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                'ppt'           => 'application/vnd.ms-powerpoint',
                'pptx'          => 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
                'csv'           => 'text/csv',
            );

            $check = wp_check_filetype_and_ext($file['tmp_name'], $file['name'], $allowed_mimes);
            $ext = !empty($check['ext']) ? strtolower($check['ext']) : '';
            $type = !empty($check['type']) ? $check['type'] : '';

            if (empty($ext) || empty($type)) {
                $this->redirect_with_error('Invalid file type.');
            }

            require_once ABSPATH . 'wp-admin/includes/file.php';

            $upload_dir = wp_upload_dir();
            $target_dir = trailingslashit($upload_dir['basedir']) . self::UPLOAD_SUBDIR;

            if (!wp_mkdir_p($target_dir)) {
                $this->redirect_with_error('Unable to create upload directory.');
            }

            $filename = wp_unique_filename($target_dir, sanitize_file_name($file['name']));
            $new_file = trailingslashit($target_dir) . $filename;

            if (!move_uploaded_file($file['tmp_name'], $new_file)) {
                $this->redirect_with_error('Could not move uploaded file.');
            }

            $user_id = get_current_user_id();
            $attachment_url = trailingslashit($upload_dir['baseurl']) . self::UPLOAD_SUBDIR . '/' . $filename;

            $attachment = array(
                'post_mime_type' => $type,
                'post_title'     => preg_replace('/\.[^.]+$/', '', $filename),
                'post_content'   => '',
                'post_status'    => 'inherit',
                'post_author'    => $user_id,
                'guid'           => $attachment_url,
            );

            $attach_id = wp_insert_attachment($attachment, $new_file);
            if (!is_wp_error($attach_id) && $attach_id) {
                require_once ABSPATH . 'wp-admin/includes/image.php';
                $attach_data = wp_generate_attachment_metadata($attach_id, $new_file);
                wp_update_attachment_metadata($attach_id, $attach_data);
            }

            update_user_meta($user_id, 'user_files_upload_last_file', esc_url_raw($attachment_url));
            update_user_meta($user_id, 'user_files_upload_last_file_id', absint($attach_id));

            $this->redirect_with_success();
        }

        private function redirect_with_success()
        {
            $redirect = wp_get_referer();
            if (!$redirect) {
                $redirect = home_url('/');
            }
            $redirect = add_query_arg(array('user_files_upload' => 'success'), $redirect);
            wp_safe_redirect($redirect);
            exit;
        }

        private function redirect_with_error($message)
        {
            $redirect = wp_get_referer();
            if (!$redirect) {
                $redirect = home_url('/');
            }
            $redirect = add_query_arg(array(
                'user_files_upload' => 'error',
                'user_files_error'  => rawurlencode($message),
            ), $redirect);
            wp_safe_redirect($redirect);
            exit;
        }
    }

    new User_Files_Upload_Plugin();
}